        _owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == _owner, "Not owner");
        _;
    }

    function setTier(address user, uint256 tier) public onlyOwner {
        _tierOf[user] = tier;
        emit TierSet(user, tier);
    }

    function tierOf(address user) public view returns (uint256) {
        return _tierOf[user];
