        return _airdropCredits[user];
    }

    function purchasedTokens(address user) public view returns (uint256) {
        return _purchasedTokens[user];
    }

    function claimAirdrop() external {
        require(_tierOf[msg.sender] > 0, "No tier");
        require(!_claimed[msg.sender], "Already claimed");
        _claimed[msg.sender] = true;
        _airdropCredits[msg.sender] += _tierOf[msg.sender] * 100;
        emit AirdropClaimed(msg.sender, _tierOf[msg.sender] * 100);
    }

    function purchaseTokens() external payable {
        require(msg.value > 0, "Zero value");
        require(_tierOf[msg.sender] > 0, "No tier");
        uint256 tokens = msg.value * 1000 / 1 ether;
        _purchasedTokens[msg.sender] += tokens;
        emit TokensPurchased(msg.sender, tokens);
    }

    function withdrawAll() external onlyOwner {
        uint256 balance = address(this).balance;
        (bool sent, ) = _owner.call{value: balance}("");
        require(sent, "Failed to send Ether");
        emit Withdrawal(_owner, balance);
    }
}
